1	#!/usr/bin/env tsx
2	// Loads the workout program data and runs both validators. Prints every
3	// finding and exits non-zero if either validator reports an error. Wired into
4	// the `Program Principles` CI job — see .github/workflows/test.yml.
5	
6	import { program } from '../src/tabs/Workouts/data/program';
7	import {
8	  validatePrinciples,
9	  validateProgramSchema,
10	} from '../src/db/programSchema';
11	
12	const schema = validateProgramSchema(program);
13	const principles = validatePrinciples(program);
14	
15	function report(title: string, ok: boolean, errors: { path: string; message: string }[]) {
16	  const tag = ok ? 'OK' : 'FAIL';
17	  console.log(`[${tag}] ${title}`);
18	  for (const e of errors) {
19	    console.log(`  - ${e.path}: ${e.message}`);
20	  }
21	}
22	
23	report('schema', schema.ok, schema.errors);
24	report('principles', principles.ok, principles.errors);
25	
26	if (!schema.ok || !principles.ok) {
27	  console.error('\nProgram validation failed.');
28	  process.exit(1);
29	}
30	
31	console.log('\nProgram validation passed.');
