#!/usr/bin/env tsx
// Static validator for the exercise catalog (src/data/exerciseCatalog.ts).
// Runs in CI via the `Catalog Validation` job — see .github/workflows/test.yml.
// Workout programs are runtime data and are not validated here; the schema
// validators (src/db/programSchema.ts) cover those at the point they enter
// the app via import.
//
// Rules enforced:
//   1. Every entry has id, name, and a non-empty muscleGroups array.
//   2. Each entry's `id` field matches its object key.
//   3. Names are unique across the catalog.
//   4. Ids are kebab-case (lowercase letters, digits, hyphens — no leading
//      or trailing hyphen, no consecutive hyphens).

import { EXERCISE_CATALOG } from '../src/data/exerciseCatalog';

interface Finding {
  id: string;
  message: string;
}

const KEBAB = /^[a-z0-9]+(-[a-z0-9]+)*$/;

const findings: Finding[] = [];
const seenNames = new Map<string, string>();

for (const [key, entry] of Object.entries(EXERCISE_CATALOG)) {
  if (typeof entry.id !== 'string' || entry.id.length === 0) {
    findings.push({ id: key, message: 'missing id' });
  } else if (entry.id !== key) {
    findings.push({
      id: key,
      message: `id "${entry.id}" does not match object key "${key}"`,
    });
  }
  if (typeof entry.name !== 'string' || entry.name.length === 0) {
    findings.push({ id: key, message: 'missing name' });
  } else {
    const nameKey = entry.name.trim().toLowerCase();
    const prior = seenNames.get(nameKey);
    if (prior) {
      findings.push({
        id: key,
        message: `duplicate name "${entry.name}" — also used by "${prior}"`,
      });
    } else {
      seenNames.set(nameKey, key);
    }
  }
  if (!Array.isArray(entry.muscleGroups) || entry.muscleGroups.length === 0) {
    findings.push({ id: key, message: 'muscleGroups must be a non-empty array' });
  }
  if (typeof entry.id === 'string' && !KEBAB.test(entry.id)) {
    findings.push({
      id: key,
      message: `id "${entry.id}" is not kebab-case`,
    });
  }
}

if (findings.length === 0) {
  console.log(
    `Catalog validation passed — ${Object.keys(EXERCISE_CATALOG).length} entries checked.`,
  );
  process.exit(0);
}

console.error(`Catalog validation failed — ${findings.length} finding(s):`);
for (const f of findings) {
  console.error(`  - ${f.id}: ${f.message}`);
}
process.exit(1);

