import { test, expect } from '@playwright/test';
import { readFileSync } from 'node:fs';
import { fileURLToPath } from 'node:url';
import { dirname, join } from 'node:path';

import { EXERCISE_CATALOG } from '../src/data/exerciseCatalog';
import {
  validatePrinciples,
  validateProgramSchema,
} from '../src/db/programSchema';

const __dirname = dirname(fileURLToPath(import.meta.url));
const FIXTURES = join(__dirname, 'fixtures');

function loadFixture(name: string): unknown {
  return JSON.parse(readFileSync(join(FIXTURES, name), 'utf-8'));
}

// These tests are pure module-level assertions — they don't drive a browser.
// Playwright is still the harness so all tests run under the same runner / CI
// job, but no page object is touched.
test.describe('program schema + principles validators', () => {
  test('program-valid.json passes both validators', () => {
    const program = loadFixture('program-valid.json');
    const schema = validateProgramSchema(program, EXERCISE_CATALOG);
    const principles = validatePrinciples(program);
    expect(schema.errors).toEqual([]);
    expect(schema.ok).toBe(true);
    expect(principles.errors).toEqual([]);
    expect(principles.ok).toBe(true);
  });

  test('program-missing-mobility.json — principles flags the phase', () => {
    const program = loadFixture('program-missing-mobility.json');
    const schema = validateProgramSchema(program, EXERCISE_CATALOG);
    const principles = validatePrinciples(program);

    // Schema itself is fine — every exercise_id is in the catalog.
    expect(schema.ok).toBe(true);
    expect(principles.ok).toBe(false);
    const finding = principles.errors.find((e) => e.path === 'phases[0]');
    expect(finding).toBeDefined();
    expect(finding!.message).toContain('no mobility-focused workout');
  });

  test('program-missing-principles.json — principles flags the missing principle', () => {
    const program = loadFixture('program-missing-principles.json');
    const principles = validatePrinciples(program);
    expect(principles.ok).toBe(false);
    const finding = principles.errors.find(
      (e) => e.path === 'meta.principles',
    );
    expect(finding).toBeDefined();
    expect(finding!.message).toContain('mobility_every_phase');
  });

  test('program-unknown-exercise.json — schema flags the unknown exercise_id', () => {
    const program = loadFixture('program-unknown-exercise.json');
    const schema = validateProgramSchema(program, EXERCISE_CATALOG);
    expect(schema.ok).toBe(false);
    const finding = schema.errors.find((e) =>
      e.message.includes('barbell-bench-press'),
    );
    expect(finding).toBeDefined();
    expect(finding!.message).toContain('not in catalog');
  });

  test('catalog cross-reference is opt-in (no catalog argument = no cross-ref)', () => {
    const program = loadFixture('program-unknown-exercise.json');
    // Without the catalog, the schema validator should NOT complain about
    // unknown exercise_ids — the cross-ref is the catalog's job.
    const schema = validateProgramSchema(program);
    const unknownFinding = schema.errors.find((e) =>
      e.message.includes('barbell-bench-press'),
    );
    expect(unknownFinding).toBeUndefined();
  });
});

